const headers = $input.item.json.headers || {};
const body = $input.item.json.body || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { _unauthorized: true, status: 401, error: 'Missing session token' } };
const required = ['advisor_id','carrier_name','policy_number','coverage_amount','effective_date','expires_date'];
for (const f of required) { if (!body[f]) return { json: { _empty: true, status: 400, error: f + ' required' } }; }
const MIN_COVERAGE = 200000000; // $2M in cents
const coverage = parseInt(body.coverage_amount) || 0;
if (coverage < MIN_COVERAGE) return { json: { _empty: true, status: 400, error: 'coverage_amount must be at least $2,000,000 ($' + (MIN_COVERAGE/100).toLocaleString() + ' cents = ' + MIN_COVERAGE + ')' } };
return { json: { token: token, advisor_id: body.advisor_id, carrier_name: body.carrier_name, policy_number: String(body.policy_number), coverage_amount: coverage, effective_date: body.effective_date, expires_date: body.expires_date, documentation_url: body.documentation_url || null } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? (rows[0] || null) : (rows && (rows.user_id || rows.id) ? rows : null);
if (!row) return { json: { _unauthorized: true, status: 401, error: 'Invalid session' } };
const allowed = ['advisor','mga_principal','admin'];
if (allowed.indexOf(row.user_role) < 0) return { json: { _unauthorized: true, status: 403, error: 'Role not permitted' } };
const crypto = require('crypto');
const keyB64 = process.env.LICENSE_ENCRYPTION_KEY || '';
let encrypted = '';
if (keyB64) {
  try {
    const key = Buffer.from(keyB64, 'base64');
    const iv = crypto.randomBytes(12);
    const cipher = crypto.createCipheriv('aes-256-gcm', key, iv);
    const c = Buffer.concat([cipher.update($('Extract + Validate Coverage').item.json.policy_number, 'utf8'), cipher.final()]);
    const tag = cipher.getAuthTag();
    encrypted = Buffer.concat([iv, tag, c]).toString('base64');
  } catch (e) { encrypted = ''; }
}
if (!encrypted) encrypted = 'PLAINTEXT_NO_KEY:' + Buffer.from($('Extract + Validate Coverage').item.json.policy_number).toString('base64');
const i = $('Extract + Validate Coverage').item.json;
return { json: { _ok: true, verifier_id: row.id || row.user_id, advisor_id: i.advisor_id, carrier_name: i.carrier_name, policy_number_encrypted: encrypted, policy_number_last4: String(i.policy_number).slice(-4), coverage_amount: i.coverage_amount, effective_date: i.effective_date, expires_date: i.expires_date, documentation_url: i.documentation_url } };
